<script setup lang="ts">import { ref, onMounted } from 'vue'import { ElMessage } from 'element-plus'import { parseResponseJson } from '@/utils/parseApiResponse'interface Evidence {  filename: string  page: number  content: string  relevance: number  confidence: number}interface ConflictDetail {  description?: string  field?: string  values?: string[]}interface QueryResult {  answer: string  confidence: number  sources: Evidence[]  hasConflicts: boolean  conflictCount: number  conflictDetails: ConflictDetail[]  explanation: {    why: string    alternatives: string    credibility: string  }}const query = ref('')const fileIds = ref<string[]>([])const filesList = ref<{ file_id: string; filename: string; status: string }[]>([])const loading = ref(false)const expandedSources = ref<Set<number>>(new Set())const result = ref<QueryResult | null>(null)const toggleSource = (index: number) => {  if (expandedSources.value.has(index)) {    expandedSources.value.delete(index)  } else {    expandedSources.value.add(index)  }}const getConfidenceColor = (confidence: number) => {  if (confidence >= 70) return 'text-green'  if (confidence >= 50) return 'text-accent'  if (confidence >= 30) return 'text-yellow-500'  return 'text-red'}const getRelevanceColor = (relevance: number) => {  if (relevance >= 70) return 'bg-green/10 text-green'  if (relevance >= 50) return 'bg-accent/10 text-accent'  if (relevance >= 30) return 'bg-yellow-500/10 text-yellow-600'  return 'bg-red/10 text-red'}/** 鏈壒妫€绱㈢墖娈电殑 RRF 鍒嗙粷瀵瑰€煎皬锛屾槧灏勪负鐗囨涔嬮棿鐨勭浉瀵广€岀浉鍏冲害銆嶇櫨鍒嗘暟锛岄伩鍏嶆棤 score 鏃惰鏄剧ず 80% */function relativeRelevancePercents(raw: number[]): number[] {  if (!raw.length) return []  const lo = Math.min(...raw)  const hi = Math.max(...raw)  const den = hi - lo  if (den < 1e-12) {    const mid = Math.min(88, Math.max(32, Math.round(lo * 1600)))    return raw.map(() => mid)  }  return raw.map(v => Math.round(36 + ((v - lo) / den) * 58))}// 鍏抽敭璇嶉珮浜?const escapeHtml = (str: string): string =>  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')const highlightContent = (content: string, queryText: string): string => {  if (!queryText || !content) return escapeHtml(content)  const words = queryText.trim().split(/\s+/).filter(w => w.length > 1)  let highlighted = escapeHtml(content)  for (const word of words) {    const escaped = word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')    highlighted = highlighted.replace(      new RegExp(escaped, 'gi'),      match => `<mark class="bg-yellow-200 rounded px-0.5">${match}</mark>`    )  }  return highlighted}const handleQuery = async () => {  if (!query.value.trim()) {    ElMessage.warning('璇疯緭鍏ラ棶棰?)    return  }  loading.value = true  expandedSources.value.clear()  try {    const response = await fetch('/api/ask', {      method: 'POST',      headers: { 'Content-Type': 'application/json' },      body: JSON.stringify({        query: query.value,        file_ids: fileIds.value,      }),    })    const data = (await parseResponseJson(response)) as Record<string, any>    if (!response.ok) {      throw new Error(data.detail || data.message || `鏌ヨ澶辫触 (${response.status})`)    }    const sourcesRaw = data.sources || []    const rawScores = sourcesRaw.map((s: any) => Number(s.score ?? s.hybrid_score ?? 0))    const relPercents = relativeRelevancePercents(rawScores)    const confidence = typeof data.confidence === 'number' && data.confidence >= 0      ? Math.round(data.confidence * 100)      : 0    const hasConflicts = data.fusion?.has_conflicts || false    const conflictCount = data.fusion?.conflict_count || 0    const conflictDetails = data.fusion?.conflict_details || []    const seenFiles = new Set<string>()    const uniqueSources = sourcesRaw      .map((s: any, i: number) => ({        s,        rel: relPercents[i] ?? 0,        fn: extractFilename(s.source_file || s.filename || ''),      }))      .filter(({ fn }) => {        if (seenFiles.has(fn)) return false        seenFiles.add(fn)        return true      })      .map(({ s, rel, fn }) => ({        filename: fn,        page: s.page || 0,        content: s.content || '',        relevance: rel,        confidence,      }))    result.value = {      answer: data.answer || '鏃犳硶鐢熸垚绛旀',      confidence,      hasConflicts,      conflictCount,      conflictDetails,      sources: uniqueSources,      explanation: {        why: hasConflicts          ? `妫€娴嬪埌 ${conflictCount} 澶勪俊鎭啿绐侊紝绯荤粺宸茶瀺鍚堝婧愪俊鎭粰鍑虹瓟妗坄          : '鍩轰簬妫€绱㈠埌鐨勬枃妗ｇ墖娈电敓鎴愮瓟妗堬紝鐩稿叧搴﹂珮',        alternatives: hasConflicts          ? conflictDetails.map((c: any) => c.description || c.field || c.key).filter(Boolean).join('锛?) || '瀛樺湪澶氭簮鍐茬獊'          : '鏈彂鐜版槑鏄惧啿绐佷俊鎭?,        credibility: confidence >= 70          ? '绛旀缃俊搴﹂珮锛屾潵婧愬彲闈?          : '绛旀浠呬緵鍙傝€冿紝寤鸿杩涗竴姝ユ牳瀹?,      },    }    ElMessage.success('鏌ヨ鎴愬姛')  } catch (error: any) {    ElMessage.error(error.message || '鏌ヨ澶辫触')  } finally {    loading.value = false  }}const handleRefresh = async () => {  try {    const response = await fetch('/api/files')    const data = (await parseResponseJson(response)) as { files?: any[] }    if (!response.ok) {      ElMessage.error((data as any).detail || `鍒锋柊鏂囦欢鍒楄〃澶辫触 (${response.status})`)      return    }    filesList.value = (data.files || []).filter((f: any) => f.status === 'indexed')  } catch (e: any) {    ElMessage.error(e?.message || '鍒锋柊鏂囦欢鍒楄〃澶辫触')  }}// 娓呴櫎鍏ㄩ儴闂瓟缂撳瓨const handleClearCache = async () => {  if (!confirm('纭畾娓呴櫎鎵€鏈夐棶绛旂紦瀛橈紵杩欎笉褰卞搷宸插叆搴撶殑鏂囨。銆?)) return  try {    const res = await fetch('/api/cache/clear', { method: 'POST' })    const data = (await parseResponseJson(res)) as Record<string, any>    if (!res.ok) throw new Error(data.detail || '娓呯紦瀛樺け璐?)    ElMessage.success(`宸叉竻闄?${data.cleared ?? 0} 鏉＄紦瀛榒)  } catch (e: any) {    ElMessage.error(e.message || '娓呯紦瀛樺け璐?)  }}const toggleFile = (fileId: string) => {  const idx = fileIds.value.indexOf(fileId)  if (idx === -1) fileIds.value.push(fileId)  else fileIds.value.splice(idx, 1)}const extractFilename = (path: string) => {  if (!path) return '鏈煡鏂囦欢'  return path.replace(/\\/g, '/').split('/').pop() || path}// 椤甸潰鎵撳紑鏃跺姞杞斤紝涔嬪悗姣?0绉掕嚜鍔ㄥ埛鏂版枃浠跺垪琛?onMounted(() => {  handleRefresh()  setInterval(handleRefresh, 10000)})</script><template>  <div class="space-y-6">    <div class="text-xs font-bold tracking-widest text-muted uppercase pb-2.5 border-b border-border-l">      澶氭簮鏂囨。鏅鸿兘闂瓟涓庢函婧?    </div>    <!-- 鏌ヨ杈撳叆 -->    <div class="grid grid-cols-12 gap-4">      <div class="col-span-7">        <label class="block text-sm font-medium text-text2 mb-2">杈撳叆鎮ㄧ殑闂</label>        <textarea          v-model="query"          class="w-full h-20 px-3 py-2 bg-white border border-border rounded-md text-sm text-text resize-none focus:border-accent focus:outline-none"          placeholder="渚嬶細鍚堝悓鎬婚噾棰濇槸澶氬皯锛熶粯娆炬柟寮忔槸浠€涔堬紵"        ></textarea>      </div>      <div class="col-span-4">        <div class="flex items-center justify-between mb-2">          <label class="block text-sm font-medium text-text2">闄愬畾鏂囨。锛堢暀绌哄垯鍏ㄥ簱妫€绱級</label>          <button @click="handleRefresh" class="text-xs text-accent hover:underline">鍒锋柊</button>          <button @click="handleClearCache" class="text-xs text-red hover:underline">娓呯紦瀛?/button>        </div>        <div class="bg-white border border-border rounded-md divide-y divide-border max-h-32 overflow-y-auto">          <div v-if="filesList.length === 0" class="px-3 py-2 text-xs text-muted">鏆傛棤宸茬储寮曟枃妗?/div>          <label            v-for="f in filesList"            :key="f.file_id"            class="flex items-center gap-2 px-3 py-2 text-xs cursor-pointer hover:bg-surface2 transition-colors"            :class="fileIds.includes(f.file_id) ? 'bg-accent/5' : ''"          >            <input              type="checkbox"              :value="f.file_id"              :checked="fileIds.includes(f.file_id)"              @change="toggleFile(f.file_id)"              class="accent-accent w-3.5 h-3.5 flex-shrink-0"            />            <span class="truncate" :class="fileIds.includes(f.file_id) ? 'text-accent font-medium' : 'text-text'">              {{ f.filename }}            </span>          </label>        </div>        <div class="mt-1 text-xs text-muted">          宸查€?{{ fileIds.length }} / {{ filesList.length }} 涓枃妗?        </div>      </div>      <div class="col-span-1 flex items-end">        <button          @click="handleQuery"          :disabled="loading"          class="w-full px-4 py-2 bg-accent text-white font-medium rounded-md hover:bg-blue-600 disabled:opacity-50 transition-colors"        >          {{ loading ? '鏌ヨ涓?..' : '寮€濮嬮棶绛? }}        </button>      </div>    </div>    <!-- 鏌ヨ缁撴灉 -->    <div v-if="result" class="space-y-6">      <!-- 鍐茬獊璀﹀憡妯箙 -->      <div        v-if="result.hasConflicts"        class="bg-yellow-50 border border-yellow-300 rounded-lg p-4 flex items-start gap-3"      >        <span class="text-xl flex-shrink-0">鈿狅笍</span>        <div>          <div class="text-sm font-bold text-yellow-800 mb-1">            澶氭簮淇℃伅鍐茬獊锛坽{ result.conflictCount }} 澶勶級          </div>          <div class="text-xs text-yellow-700">            {{ result.conflictDetails.map((c: any) => c.description || c.field || c.key).filter(Boolean).join('锛?) || '澶氫釜鏉ユ簮瀛樺湪鐭涚浘锛屽缓璁汉宸ユ牳瀹? }}          </div>        </div>      </div>      <!-- 绛旀鍗＄墖 -->      <div class="bg-white border border-border rounded-lg p-6">        <div class="flex items-start justify-between mb-4">          <div>            <h3 class="text-sm font-bold text-text mb-1">馃挕 绛旀</h3>            <p class="text-xs text-muted">鍩轰簬澶氭簮鏂囨。鐨勬櫤鑳介棶绛旂粨鏋?/p>          </div>          <div class="text-right">            <div class="text-2xl font-bold" :class="getConfidenceColor(result.confidence)">              {{ result.confidence }}%            </div>            <div class="text-xs text-muted">缃俊搴?/div>          </div>        </div>        <div class="bg-surface2 rounded-lg p-4 text-sm text-text leading-relaxed whitespace-pre-wrap">          {{ result.answer }}        </div>      </div>      <!-- 璇佹嵁鏉ユ簮 -->      <div>        <div class="text-xs font-bold tracking-widest text-muted uppercase pb-2.5 border-b border-border-l mb-4">          馃搫 璇佹嵁鏉ユ簮锛坽{ result.sources.length }} 涓級        </div>        <div class="space-y-3">          <div            v-for="(source, index) in result.sources"            :key="index"            class="bg-white border border-border rounded-lg overflow-hidden hover:border-accent transition-colors"          >            <!-- 璇佹嵁澶撮儴 -->            <div              @click="toggleSource(index)"              class="p-4 cursor-pointer hover:bg-surface2 transition-colors flex items-center justify-between"            >              <div class="flex-1">                <div class="flex items-center gap-3 mb-2">                  <span class="font-medium text-text">{{ source.filename }}</span>                  <span class="text-xs px-2 py-1 rounded" :class="getRelevanceColor(source.relevance)">                    鐩稿叧搴?{{ source.relevance }}%                  </span>                </div>                <div class="text-xs text-muted">绗?{{ source.page }} 椤?/div>              </div>              <div class="text-lg">                {{ expandedSources.has(index) ? '鈻? : '鈻? }}              </div>            </div>            <!-- 璇佹嵁鍐呭锛堝睍寮€鏃舵樉绀猴紝鍚叧閿瘝楂樹寒锛?-->            <div v-if="expandedSources.has(index)" class="border-t border-border-l bg-surface2 p-4 space-y-3">              <div>                <div class="text-xs font-semibold text-text2 mb-2">鍘熸枃鍐呭锛堝叧閿瘝宸查珮浜級</div>                <div                  class="bg-white border border-border rounded p-3 text-sm text-text leading-relaxed"                  v-html="highlightContent(source.content, query)"                ></div>              </div>              <div class="grid grid-cols-3 gap-3">                <div class="bg-white border border-border rounded p-3">                  <div class="text-xs text-muted mb-1">鐩稿叧搴?/div>                  <div class="text-lg font-bold text-accent">{{ source.relevance }}%</div>                </div>                <div class="bg-white border border-border rounded p-3">                  <div class="text-xs text-muted mb-1">缃俊搴?/div>                  <div class="text-lg font-bold text-accent">{{ source.confidence }}%</div>                </div>                <div class="bg-white border border-border rounded p-3">                  <div class="text-xs text-muted mb-1">鏉ユ簮鏂囦欢</div>                  <div class="text-sm font-medium text-text truncate" :title="source.filename">{{ source.filename }}</div>                </div>              </div>              <div class="flex gap-2">                <button                  @click="() => { navigator.clipboard.writeText(source.content); ElMessage.success('宸插鍒?) }"                  class="flex-1 px-3 py-2 bg-accent/10 text-accent text-sm font-medium rounded hover:bg-accent/20 transition-colors"                >                  馃搵 澶嶅埗鍘熸枃                </button>              </div>            </div>          </div>        </div>      </div>      <!-- 瑙ｉ噴鎬т俊鎭?-->      <div class="grid grid-cols-3 gap-4">        <div class="bg-white border border-border rounded-lg p-4">          <div class="flex items-center gap-2 mb-3">            <span class="text-lg">鉂?/span>            <h4 class="text-sm font-bold text-text">涓轰粈涔堥€夎繖涓瓟妗堬紵</h4>          </div>          <p class="text-xs text-text2 leading-relaxed">            {{ result.explanation.why }}          </p>        </div>        <div class="bg-white border border-border rounded-lg p-4" :class="result.hasConflicts ? 'border-yellow-300 bg-yellow-50' : ''">          <div class="flex items-center gap-2 mb-3">            <span class="text-lg">{{ result.hasConflicts ? '鈿狅笍' : '馃攧' }}</span>            <h4 class="text-sm font-bold text-text">{{ result.hasConflicts ? '鍐茬獊淇℃伅' : '杩樻湁鍏朵粬鍙兘鍚楋紵' }}</h4>          </div>          <p class="text-xs text-text2 leading-relaxed">            {{ result.explanation.alternatives }}          </p>        </div>        <div class="bg-white border border-border rounded-lg p-4">          <div class="flex items-center gap-2 mb-3">            <span class="text-lg">鉁?/span>            <h4 class="text-sm font-bold text-text">鏁版嵁鍙俊搴︼紵</h4>          </div>          <p class="text-xs text-text2 leading-relaxed">            {{ result.explanation.credibility }}          </p>        </div>      </div>    </div>    <!-- 绌虹姸鎬?-->    <div v-else class="bg-surface2 border-2 border-dashed border-border rounded-lg p-12 text-center">      <div class="text-4xl mb-3">馃挰</div>      <div class="text-sm text-text2">杈撳叆闂骞剁偣鍑?寮€濮嬮棶绛?锛岀郴缁熷皢涓烘偍妫€绱㈠婧愭枃妗ｅ苟鐢熸垚绛旀</div>    </div>  </div></template><style scoped></style>